export type Mesa = {
  id: number;
  numero: number;
  estado: string;
};

// Variable para almacenar las mesas en memoria
let mesas: Mesa[] = [];

export async function getMesas(): Promise<Mesa[]> {
  return mesas;
}

export async function agregarMesa(mesa: Omit<Mesa, "id">) {
  const nuevaMesa = { ...mesa, id: Date.now() };
  mesas.push(nuevaMesa);
  return nuevaMesa;
}

export async function eliminarMesa(id: number) {
  mesas = mesas.filter((m) => m.id !== id);
}

export async function editarMesa(id: number, mesa: Omit<Mesa, "id">) {
  const index = mesas.findIndex((m) => m.id === id);
  if (index !== -1) {
    mesas[index] = { ...mesa, id };
  }
}
